namespace sv_0800ff6ce19a442d9baa64c72404feba.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella and basil.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg, and pecorino.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp, peanuts, and tamarind sauce.", 20),
            new(5, "Green Curry", "Coconut milk curry with Thai basil, bamboo shoots, and chicken.", 35),
            new(6, "Mango Sticky Rice", "Sweet sticky rice topped with fresh mango and coconut cream.", 40),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple and fresh cilantro.", 50),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and jalapeño.", 10),
            new(9, "Churros", "Fried dough sticks coated in cinnamon sugar with chocolate sauce.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_0800ff6ce19a442d9baa64c72404feba.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IAsyncDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes =>
        Sort?.ToLowerInvariant() switch
        {
            "popular" => _recipes!.OrderByDescending(r => r.Id),
            "newest" => _recipes!.OrderByDescending(r => r.PrepTimeMinutes),
            _ => _recipes!
        };

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId)
        {
            // Only sort changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request for a previous cuisine.
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            // If cancelled between awaits, don't apply stale results.
            token.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException)
        {
            // Request was superseded — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }
}

